  64→#[instrument(skip(config), fields(account_id, homeserver = %config.homeserver))]
  65→pub(crate) async fn build_client(
  66→    account_id: &str,
  67→    config: &MatrixAccountConfig,
  68→) -> ChannelResult<Client> {
  69→    let store_path = ensure_store_path(account_id)?;
  70→    Client::builder()
  71→        .homeserver_url(&config.homeserver)
  72→        .with_encryption_settings(encryption_settings())
  73→        .sqlite_store(&store_path, None)
  74→        .build()
  75→        .await
  76→        .map_err(|error| ChannelError::external("matrix client build", error))
  77→}
