  79→#[instrument(skip(config), fields(account_id))]
  80→pub(crate) async fn build_and_authenticate_client(
  81→    account_id: &str,
  82→    config: &MatrixAccountConfig,
  83→) -> ChannelResult<(Client, AuthenticatedMatrixAccount)> {
  84→    let client = build_client(account_id, config).await?;
  85→    match authenticate_client(&client, account_id, config).await {
  86→        Ok(authenticated) => Ok((client, authenticated)),
  87→        Err(error) if should_rebuild_store_after_auth_error(config, &error) => {
  88→            warn!(
  89→                account_id,
  90→                "matrix crypto store is pinned to an old device, resetting local store and retrying login once"
  91→            );
  92→            reset_store_path(account_id)?;
  93→            let client = build_client(account_id, config).await?;
  94→            let authenticated = authenticate_client(&client, account_id, config).await?;
  95→            Ok((client, authenticated))
  96→        },
  97→        Err(error) => Err(error),
  98→    }
  99→}
