 101→fn encryption_settings() -> EncryptionSettings {
 102→    EncryptionSettings {
 103→        auto_enable_cross_signing: true,
 104→        backup_download_strategy: BackupDownloadStrategy::AfterDecryptionFailure,
 105→        ..Default::default()
 106→    }
 107→}
 108→
 109→fn should_rebuild_store_after_auth_error(
 110→    config: &MatrixAccountConfig,
 111→    error: &ChannelError,
 112→) -> bool {
 113→    matches!(auth_mode(config), Ok(AuthMode::Password))
 114→        && matches!(
 115→            error,
 116→            ChannelError::External { context, source }
 117→                if context == "matrix password login"
 118→                    && source
 119→                        .to_string()
 120→                        .contains("the account in the store doesn't match the account in the constructor")
 121→        )
 122→}
