 124→pub(crate) fn auth_mode(config: &MatrixAccountConfig) -> ChannelResult<AuthMode> {
 125→    let access_token = config.access_token.expose_secret().trim();
 126→    if !access_token.is_empty() && access_token != moltis_common::secret_serde::REDACTED {
 127→        return Ok(AuthMode::AccessToken);
 128→    }
 129→
 130→    let password = config
 131→        .password
 132→        .as_ref()
 133→        .map(|secret| secret.expose_secret().trim())
 134→        .unwrap_or_default();
 135→    if password.is_empty() || password == moltis_common::secret_serde::REDACTED {
 136→        return Err(ChannelError::invalid_input(
 137→            "either access_token or password is required",
 138→        ));
 139→    }
 140→
 141→    if config.user_id.as_deref().is_none_or(str::is_empty) {
 142→        return Err(ChannelError::invalid_input(
 143→            "user_id is required when using password authentication",
 144→        ));
 145→    }
 146→
 147→    Ok(AuthMode::Password)
 148→}
