 150→#[instrument(skip(client, config), fields(account_id))]
 151→pub(crate) async fn authenticate_client(
 152→    client: &Client,
 153→    account_id: &str,
 154→    config: &MatrixAccountConfig,
 155→) -> ChannelResult<AuthenticatedMatrixAccount> {
 156→    match auth_mode(config)? {
 157→        AuthMode::AccessToken => {
 158→            let identity = restore_access_token_session(client, account_id, config).await?;
 159→            client
 160→                .encryption()
 161→                .wait_for_e2ee_initialization_tasks()
 162→                .await;
 163→            info!(
 164→                account_id,
 165→                user_id = %identity.user_id,
 166→                device_id = identity.device_id.as_deref().unwrap_or("<unknown>"),
 167→                "matrix session restored"
 168→            );
 169→            Ok(AuthenticatedMatrixAccount {
 170→                user_id: identity.user_id,
 171→                ownership_startup_error: None,
 172→            })
 173→        },
 174→        AuthMode::Password => {
 175→            login_with_password(client, account_id, config).await?;
 176→            client
 177→                .encryption()
 178→                .wait_for_e2ee_initialization_tasks()
 179→                .await;
 180→            let bot_user_id = client
 181→                .whoami()
 182→                .await
 183→                .map_err(|error| ChannelError::external("matrix whoami", error))?
 184→                .user_id;
 185→            info!(account_id, user_id = %bot_user_id, "matrix password login complete");
 186→            Ok(AuthenticatedMatrixAccount {
 187→                user_id: bot_user_id,
 188→                ownership_startup_error: None,
 189→            })
 190→        },
 191→    }
 192→}
