 194→pub(crate) async fn maybe_take_matrix_account_ownership(
 195→    client: &Client,
 196→    account_id: &str,
 197→    config: &MatrixAccountConfig,
 198→) -> OwnershipAttemptResult {
 199→    if config.ownership_mode != MatrixOwnershipMode::MoltisOwned {
 200→        return OwnershipAttemptResult::default();
 201→    }
 202→
 203→    match ensure_moltis_owned_encryption_state(client, account_id, config).await {
 204→        Ok(Some(handle)) => {
 205→            let startup_error = ownership_approval_message(&handle);
 206→            warn!(
 207→                account_id,
 208→                error = startup_error,
 209→                "matrix ownership setup failed"
 210→            );
 211→            OwnershipAttemptResult {
 212→                startup_error: Some(startup_error),
 213→                pending_identity_reset: Some(handle),
 214→            }
 215→        },
 216→        Ok(None) => OwnershipAttemptResult::default(),
 217→        Err(error) => {
 218→            warn!(account_id, error = %error, "matrix ownership setup failed");
 219→            OwnershipAttemptResult {
 220→                startup_error: Some(error.to_string()),
 221→                pending_identity_reset: None,
 222→            }
 223→        },
 224→    }
 225→}
