 234→async fn ownership_is_ready(client: &Client) -> ChannelResult<bool> {
 235→    Ok(ownership_is_effectively_ready(
 236→        cross_signing_is_complete(client).await,
 237→        own_device_is_cross_signed_by_owner(client).await?,
 238→    ))
 239→}
