 241→async fn try_recover_secret_storage_with_password(
 242→    client: &Client,
 243→    account_id: &str,
 244→    password: &str,
 245→) -> bool {
 246→    match client.encryption().recovery().recover(password).await {
 247→        Ok(()) => {
 248→            wait_for_e2ee_state_to_settle(client).await;
 249→            info!(
 250→                account_id,
 251→                "matrix ownership recovered existing secret storage with account password"
 252→            );
 253→            true
 254→        },
 255→        Err(error) => {
 256→            warn!(
 257→                account_id,
 258→                error = %error,
 259→                "matrix ownership could not recover existing secret storage with account password"
 260→            );
 261→            false
 262→        },
 263→    }
 264→}
