 266→#[instrument(skip(client, config), fields(account_id))]
 267→async fn ensure_moltis_owned_encryption_state(
 268→    client: &Client,
 269→    account_id: &str,
 270→    config: &MatrixAccountConfig,
 271→) -> ChannelResult<Option<IdentityResetHandle>> {
 272→    let Some(user_id) = config
 273→        .user_id
 274→        .as_deref()
 275→        .filter(|user_id| !user_id.is_empty())
 276→    else {
 277→        return Err(ChannelError::invalid_input(
 278→            "user_id is required when Moltis owns a Matrix account",
 279→        ));
 280→    };
 281→    let Some(password) = config.password.as_ref() else {
 282→        return Err(ChannelError::invalid_input(
 283→            "password is required when Moltis owns a Matrix account",
 284→        ));
 285→    };
 286→
 287→    bootstrap_cross_signing_with_password(client, user_id, password.expose_secret()).await?;
 288→
 289→    if !ownership_is_ready(client).await? {
 290→        wait_for_e2ee_state_to_settle(client).await;
 291→    }
 292→
 293→    let initial_recovery_state = client.encryption().recovery().state();
 294→    if should_try_recover_existing_secret_storage(
 295→        ownership_is_ready(client).await?,
 296→        initial_recovery_state,
 297→    ) {
 298→        let _ =
 299→            try_recover_secret_storage_with_password(client, account_id, password.expose_secret())
 300→                .await;
 301→    }
 302→
 303→    if !ownership_is_ready(client).await?
 304→        && let Some(handle) =
 305→            force_take_over_existing_identity(client, account_id, user_id, password.expose_secret())
 306→                .await?
 307→    {
 308→        return Ok(Some(handle));
 309→    }
 310→
 311→    match client.encryption().recovery().state() {
 312→        RecoveryState::Disabled => {
 313→            enable_password_backed_recovery(client, password.expose_secret()).await?;
 314→            info!(
 315→                account_id,
 316→                "matrix ownership recovery enabled with password-backed secret storage"
 317→            );
 318→        },
 319→        RecoveryState::Enabled => {
 320→            info!(account_id, "matrix ownership recovery already enabled");
 321→        },
 322→        RecoveryState::Incomplete => {
 323→            if !try_recover_secret_storage_with_password(
 324→                client,
 325→                account_id,
 326→                password.expose_secret(),
 327→            )
 328→            .await
 329→            {
 330→                force_take_over_existing_identity(
 331→                    client,
 332→                    account_id,
 333→                    user_id,
 334→                    password.expose_secret(),
 335→                )
 336→                .await?;
 337→            }
 338→        },
 339→        RecoveryState::Unknown => {
 340→            warn!(
 341→                account_id,
 342→                "matrix recovery state is still unknown after login, skipping automatic ownership bootstrap"
 343→            );
 344→        },
 345→    }
 346→
 347→    ensure_own_device_is_cross_signed(client).await?;
 348→
 349→    if !ownership_is_ready(client).await? {
 350→        return Err(ChannelError::invalid_input(
 351→            "matrix ownership bootstrap completed but cross-signing is still incomplete",
 352→        ));
 353→    }
 354→
 355→    Ok(None)
 356→}
 357→
 358→async fn enable_password_backed_recovery(client: &Client, password: &str) -> ChannelResult<String> {
 359→    let recovery_key = client
 360→        .encryption()
 361→        .recovery()
 362→        .enable()
 363→        .wait_for_backups_to_upload()
 364→        .with_passphrase(password)
 365→        .await
 366→        .map_err(|error| ChannelError::external("matrix recovery enable", error))?;
 367→    wait_for_e2ee_state_to_settle(client).await;
 368→    Ok(recovery_key)
 369→}
 370→
 371→async fn ensure_own_device_is_cross_signed(client: &Client) -> ChannelResult<()> {
 372→    if own_device_is_cross_signed_by_owner(client).await? {
 373→        return Ok(());
 374→    }
 375→
 376→    let Some(own_device) = client
 377→        .encryption()
 378→        .get_own_device()
 379→        .await
 380→        .map_err(|error| ChannelError::external("matrix own device lookup", error))?
 381→    else {
 382→        return Ok(());
 383→    };
 384→
 385→    own_device
 386→        .verify()
 387→        .await
 388→        .map_err(|error| ChannelError::external("matrix own device self-sign", error))
 389→}
 390→
 391→async fn own_device_is_cross_signed_by_owner(client: &Client) -> ChannelResult<bool> {
 392→    Ok(client
 393→        .encryption()
 394→        .get_own_device()
 395→        .await
 396→        .map_err(|error| ChannelError::external("matrix own device lookup", error))?
 397→        .is_some_and(|device| device.is_cross_signed_by_owner()))
 398→}
 399→
 400→fn ownership_is_effectively_ready(
 401→    cross_signing_complete: bool,
 402→    own_device_cross_signed_by_owner: bool,
 403→) -> bool {
 404→    cross_signing_complete || own_device_cross_signed_by_owner
 405→}
 406→
 407→fn should_try_recover_existing_secret_storage(
 408→    ownership_ready: bool,
 409→    recovery_state: RecoveryState,
 410→) -> bool {
 411→    !ownership_ready
 412→        && matches!(
 413→            recovery_state,
 414→            RecoveryState::Enabled | RecoveryState::Incomplete
 415→        )
 416→}
 417→
 418→async fn cross_signing_is_complete(client: &Client) -> bool {
 419→    client
 420→        .encryption()
 421→        .cross_signing_status()
 422→        .await
 423→        .is_some_and(|status| status.is_complete())
 424→}
 425→
 426→fn ownership_approval_message(handle: &IdentityResetHandle) -> String {
 427→    match handle.auth_type() {
 428→        CrossSigningResetAuthType::OAuth(info) => format!(
 429→            "matrix account requires browser approval to reset cross-signing at {}; complete that in Element or switch to user-managed mode",
 430→            info.approval_url
 431→        ),
 432→        CrossSigningResetAuthType::Uiaa(_) => {
 433→            "matrix account requires additional authentication to reset cross-signing".to_string()
 434→        },
 435→    }
 436→}
