 438→#[instrument(skip(client, password), fields(account_id))]
 439→async fn force_take_over_existing_identity(
 440→    client: &Client,
 441→    account_id: &str,
 442→    user_id: &str,
 443→    password: &str,
 444→) -> ChannelResult<Option<IdentityResetHandle>> {
 445→    let maybe_handle = client
 446→        .encryption()
 447→        .recovery()
 448→        .reset_identity()
 449→        .await
 450→        .map_err(|error| ChannelError::external("matrix recovery reset identity", error))?;
 451→
 452→    if let Some(handle) = maybe_handle {
 453→        match handle.auth_type() {
 454→            CrossSigningResetAuthType::Uiaa(uiaa) => {
 455→                let mut auth = Password::new(
 456→                    UserIdentifier::UserIdOrLocalpart(user_id.to_owned()),
 457→                    password.to_owned(),
 458→                );
 459→                auth.session = uiaa.session.clone();
 460→                handle
 461→                    .reset(Some(AuthData::Password(auth)))
 462→                    .await
 463→                    .map_err(|error| {
 464→                        ChannelError::external("matrix recovery reset identity auth", error)
 465→                    })?;
 466→                wait_for_e2ee_state_to_settle(client).await;
 467→            },
 468→            CrossSigningResetAuthType::OAuth(_) => {
 469→                return Ok(Some(handle));
 470→            },
 471→        }
 472→    }
 473→
 474→    let _recovery_key = enable_password_backed_recovery(client, password).await?;
 475→
 476→    info!(
 477→        account_id,
 478→        "matrix ownership forcibly reset existing recovery state and bootstrapped fresh Moltis-managed recovery"
 479→    );
 480→
 481→    Ok(None)
 482→}
 483→
 484→async fn bootstrap_cross_signing_with_password(
 485→    client: &Client,
 486→    user_id: &str,
 487→    password: &str,
 488→) -> ChannelResult<()> {
 489→    match client
 490→        .encryption()
 491→        .bootstrap_cross_signing_if_needed(None)
 492→        .await
 493→    {
 494→        Ok(()) => Ok(()),
 495→        Err(error) => {
 496→            let Some(response) = error.as_uiaa_response() else {
 497→                return Err(ChannelError::external(
 498→                    "matrix cross-signing bootstrap",
 499→                    error,
 500→                ));
 501→            };
 502→
 503→            let mut auth = Password::new(
 504→                UserIdentifier::UserIdOrLocalpart(user_id.to_owned()),
 505→                password.to_owned(),
 506→            );
 507→            auth.session = response.session.clone();
 508→
 509→            client
 510→                .encryption()
 511→                .bootstrap_cross_signing(Some(AuthData::Password(auth)))
 512→                .await
 513→                .map_err(|error| ChannelError::external("matrix cross-signing bootstrap", error))
 514→        },
 515→    }
 516→}
