 518→#[instrument(skip(client, accounts), fields(account_id, user_id = %bot_user_id))]
 519→pub(crate) fn register_event_handlers(
 520→    client: &Client,
 521→    account_id: &str,
 522→    accounts: &AccountStateMap,
 523→    bot_user_id: &OwnedUserId,
 524→) {
 525→    let accounts_for_msg = Arc::clone(accounts);
 526→    let account_id_msg = account_id.to_string();
 527→    let bot_uid_msg = bot_user_id.clone();
 528→    client.add_event_handler(
 529→        move |ev: matrix_sdk::ruma::events::room::message::OriginalSyncRoomMessageEvent,
 530→              room: Room| {
 531→            let accounts = Arc::clone(&accounts_for_msg);
 532→            let aid = account_id_msg.clone();
 533→            let buid = bot_uid_msg.clone();
 534→            async move {
 535→                handler::handle_room_message(ev, room, aid, accounts, buid).await;
 536→            }
 537→        },
 538→    );
 539→
 540→    let accounts_for_encrypted = Arc::clone(accounts);
 541→    let account_id_encrypted = account_id.to_string();
 542→    let bot_uid_encrypted = bot_user_id.clone();
 543→    client.add_event_handler(move |ev: OriginalSyncRoomEncryptedEvent, room: Room| {
 544→        let accounts = Arc::clone(&accounts_for_encrypted);
 545→        let aid = account_id_encrypted.clone();
 546→        let buid = bot_uid_encrypted.clone();
 547→        async move {
 548→            handler::handle_room_encrypted_event(ev, room, aid, accounts, buid).await;
 549→        }
 550→    });
 551→
 552→    let accounts_for_to_device = Arc::clone(accounts);
 553→    let account_id_to_device = account_id.to_string();
 554→    client.add_event_handler(
 555→        move |ev: matrix_sdk::ruma::events::ToDeviceEvent<
 556→            matrix_sdk::ruma::events::key::verification::request::ToDeviceKeyVerificationRequestEventContent,
 557→        >| {
 558→            let accounts = Arc::clone(&accounts_for_to_device);
 559→            let aid = account_id_to_device.clone();
 560→            async move {
 561→                verification::handle_to_device_verification_request(ev, aid, accounts).await;
 562→            }
 563→        },
 564→    );
 565→
 566→    let accounts_for_poll = Arc::clone(accounts);
 567→    let account_id_poll = account_id.to_string();
 568→    client.add_event_handler(
 569→        move |ev: matrix_sdk::ruma::events::poll::response::OriginalSyncPollResponseEvent,
 570→              room: Room| {
 571→            let accounts = Arc::clone(&accounts_for_poll);
 572→            let aid = account_id_poll.clone();
 573→            let sender_id = ev.sender.to_string();
 574→            let callback_data = handler::first_selection(&ev.content.selections);
 575→            async move {
 576→                handler::handle_poll_response(room, aid, accounts, sender_id, callback_data).await;
 577→            }
 578→        },
 579→    );
 580→
 581→    let accounts_for_unstable_poll = Arc::clone(accounts);
 582→    let account_id_unstable_poll = account_id.to_string();
 583→    client.add_event_handler(
 584→        move |ev: matrix_sdk::ruma::events::poll::unstable_response::OriginalSyncUnstablePollResponseEvent,
 585→              room: Room| {
 586→            let accounts = Arc::clone(&accounts_for_unstable_poll);
 587→            let aid = account_id_unstable_poll.clone();
 588→            let sender_id = ev.sender.to_string();
 589→            let callback_data = handler::first_selection(&ev.content.poll_response.answers);
 590→            async move {
 591→                handler::handle_poll_response(room, aid, accounts, sender_id, callback_data).await;
 592→            }
 593→        },
 594→    );
 595→
 596→    let accounts_for_invite = Arc::clone(accounts);
 597→    let account_id_invite = account_id.to_string();
 598→    let bot_uid_invite = bot_user_id.clone();
 599→    client.add_event_handler(
 600→        move |ev: matrix_sdk::ruma::events::room::member::StrippedRoomMemberEvent, room: Room| {
 601→            let accounts = Arc::clone(&accounts_for_invite);
 602→            let aid = account_id_invite.clone();
 603→            let buid = bot_uid_invite.clone();
 604→            async move {
 605→                handler::handle_invite(ev, room, aid, accounts, buid).await;
 606→            }
 607→        },
 608→    );
 609→}
