 703→fn account_store_component(account_id: &str) -> String {
 704→    let sanitized = account_id
 705→        .chars()
 706→        .map(|ch| match ch {
 707→            'a'..='z' | 'A'..='Z' | '0'..='9' | '-' | '_' => ch,
 708→            _ => '-',
 709→        })
 710→        .collect::<String>()
 711→        .trim_matches('-')
 712→        .to_string();
 713→
 714→    if sanitized.is_empty() {
 715→        "default".to_string()
 716→    } else {
 717→        sanitized
 718→    }
 719→}
