 737→async fn restore_access_token_session(
 738→    client: &Client,
 739→    account_id: &str,
 740→    config: &MatrixAccountConfig,
 741→) -> ChannelResult<AccessTokenIdentity> {
 742→    let identity = resolve_access_token_identity(config).await?;
 743→    let session = access_token_session(account_id, config, &identity);
 744→
 745→    client
 746→        .restore_session(session)
