 753→fn access_token_session(
 754→    account_id: &str,
 755→    config: &MatrixAccountConfig,
 756→    identity: &AccessTokenIdentity,
 757→) -> matrix_sdk::authentication::matrix::MatrixSession {
 758→    if config.user_id.as_deref().is_some_and(|user_id| {
 759→        let trimmed = user_id.trim();
 760→        !trimmed.is_empty() && trimmed != identity.user_id.as_str()
 761→    }) {
 762→        warn!(
 763→            account_id,
 764→            configured_user_id = config.user_id.as_deref().unwrap_or_default(),
 765→            authenticated_user_id = %identity.user_id,
 766→            "matrix configured user_id does not match token owner, using authenticated user"
 767→        );
 768→    }
 769→
 770→    if config.device_id.as_deref().is_some_and(|device_id| {
 771→        let trimmed = device_id.trim();
 772→        identity
 773→            .device_id
 774→            .as_deref()
 775→            .is_some_and(|actual_device_id| !trimmed.is_empty() && trimmed != actual_device_id)
 776→    }) {
 777→        warn!(
 778→            account_id,
 779→            configured_device_id = config.device_id.as_deref().unwrap_or_default(),
 780→            authenticated_device_id = identity.device_id.as_deref().unwrap_or_default(),
 781→            "matrix configured device_id does not match token device, using authenticated device"
 782→        );
 783→    }
 784→
 785→    let device_id = identity
 786→        .device_id
 787→        .clone()
 788→        .unwrap_or_else(|| resolved_device_id(account_id, config.device_id.as_deref()));
 789→
 790→    matrix_sdk::authentication::matrix::MatrixSession {
 791→        meta: matrix_sdk::SessionMeta {
 792→            user_id: identity.user_id.clone(),
 793→            device_id: device_id.into(),
 794→        },
 795→        tokens: matrix_sdk::SessionTokens {
 796→            access_token: config.access_token.expose_secret().clone(),
 797→            refresh_token: None,
 798→        },
 799→    }
 800→}
