 802→#[instrument(skip(config))]
 803→async fn resolve_access_token_identity(
 804→    config: &MatrixAccountConfig,
 805→) -> ChannelResult<AccessTokenIdentity> {
 806→    let homeserver = config.homeserver.trim_end_matches('/');
 807→    let whoami_url = format!("{homeserver}/_matrix/client/v3/account/whoami");
 808→    let response = reqwest::Client::new()
 809→        .get(&whoami_url)
 810→        .bearer_auth(config.access_token.expose_secret())
 811→        .send()
 812→        .await
 813→        .map_err(|error| ChannelError::external("matrix access token whoami", error))?;
 814→
 815→    let response = response
 816→        .error_for_status()
 817→        .map_err(|error| match error.status() {
 818→            Some(StatusCode::UNAUTHORIZED) => {
 819→                ChannelError::external("matrix access token whoami", error)
 820→            },
 821→            _ => ChannelError::external("matrix access token whoami", error),
 822→        })?;
 823→
 824→    let whoami = response
 825→        .json::<AccessTokenWhoAmIResponse>()
 826→        .await
 827→        .map_err(|error| ChannelError::external("matrix access token whoami decode", error))?;
 828→
 829→    Ok(AccessTokenIdentity {
 830→        user_id: whoami.user_id,
 831→        device_id: whoami
 832→            .device_id
 833→            .map(|device_id| device_id.trim().to_string())
 834→            .filter(|device_id| !device_id.is_empty()),
 835→    })
 836→}
