 838→#[instrument(skip(client, config), fields(account_id))]
 839→async fn login_with_password(
 840→    client: &Client,
 841→    account_id: &str,
 842→    config: &MatrixAccountConfig,
 843→) -> ChannelResult<()> {
 844→    let user_id = config
 845→        .user_id
 846→        .as_deref()
 847→        .filter(|user_id| !user_id.is_empty())
 848→        .ok_or_else(|| {
 849→            ChannelError::invalid_input("user_id is required when using password authentication")
 850→        })?;
 851→    let password = config
 852→        .password
 853→        .as_ref()
 854→        .map(|secret| secret.expose_secret())
 855→        .ok_or_else(|| ChannelError::invalid_input("password is required"))?;
 856→
 857→    let mut login = client.matrix_auth().login_username(user_id, password);
 858→    if let Some(device_id) = configured_device_id(config.device_id.as_deref()) {
 859→        login = login.device_id(&device_id);
 860→    }
 861→    if let Some(display_name) = config
 862→        .device_display_name
 863→        .as_deref()
 864→        .filter(|name| !name.is_empty())
 865→    {
 866→        login = login.initial_device_display_name(display_name);
 867→    }
 868→
 869→    login
 870→        .send()
 871→        .await
 872→        .map_err(|error| ChannelError::external("matrix password login", error))?;
 873→
 874→    info!(account_id, "matrix password login restored session");
 875→    Ok(())
 876→}
