 29→fn verification_state_label(state: VerificationState) -> &'static str {
 30→    match state {
 31→        VerificationState::Unknown => "unknown",
 32→        VerificationState::Verified => "verified",
 33→        VerificationState::Unverified => "unverified",
 34→    }
 35→}
 36→
 37→fn recovery_state_label(state: RecoveryState) -> &'static str {
 38→    match state {
 39→        RecoveryState::Unknown => "unknown",
 40→        RecoveryState::Enabled => "enabled",
 41→        RecoveryState::Disabled => "disabled",
 42→        RecoveryState::Incomplete => "incomplete",
 43→    }
 44→}
 45→
 46→fn ownership_mode_label(mode: MatrixOwnershipMode) -> &'static str {
 47→    match mode {
 48→        MatrixOwnershipMode::UserManaged => "user_managed",
 49→        MatrixOwnershipMode::MoltisOwned => "moltis_owned",
 50→    }
 51→}
 52→
 53→fn effective_recovery_state(
 54→    cached_state: RecoveryState,
 55→    secret_storage_enabled: bool,
 56→    cross_signing_complete: bool,
 57→    backups_enabled: bool,
 58→) -> RecoveryState {
 59→    if !secret_storage_enabled {
 60→        return if matches!(cached_state, RecoveryState::Unknown) {
 61→            RecoveryState::Unknown
 62→        } else {
 63→            RecoveryState::Disabled
 64→        };
 65→    }
 66→
 67→    if cross_signing_complete && (backups_enabled || matches!(cached_state, RecoveryState::Enabled))
 68→    {
 69→        RecoveryState::Enabled
 70→    } else {
 71→        RecoveryState::Incomplete
 72→    }
 73→}
 74→
 75→struct MatrixStatusSnapshot {
 76→    client: matrix_sdk::Client,
 77→    config: MatrixAccountConfig,
 78→    prompts: Vec<VerificationPrompt>,
 79→    startup_error: Option<String>,
 80→}
 81→
 82→async fn matrix_status_extra(snapshot: MatrixStatusSnapshot) -> serde_json::Value {
 83→    let verification_state = snapshot.client.encryption().verification_state().get();
 84→    let cached_recovery_state = snapshot.client.encryption().recovery().state();
 85→    let cross_signing_complete = snapshot
 86→        .client
 87→        .encryption()
 88→        .cross_signing_status()
 89→        .await
 90→        .is_some_and(|status| status.is_complete());
 91→    let secret_storage_enabled = snapshot
 92→        .client
 93→        .encryption()
 94→        .secret_storage()
 95→        .is_enabled()
 96→        .await
 97→        .unwrap_or(false);
 98→    let backups_enabled = snapshot.client.encryption().backups().are_enabled().await;
 99→    let device_verified_by_owner = snapshot
100→        .client
101→        .encryption()
102→        .get_own_device()
103→        .await
104→        .ok()
105→        .flatten()
106→        .is_some_and(|device| device.is_cross_signed_by_owner());
107→    let recovery_state = effective_recovery_state(
108→        cached_recovery_state,
109→        secret_storage_enabled,
110→        cross_signing_complete,
111→        backups_enabled,
112→    );
113→    serde_json::json!({
114→        "matrix": {
115→            "verification_state": verification_state_label(verification_state),
116→            "pending_verifications": snapshot.prompts.iter().map(|prompt| serde_json::json!({
117→                "flow_id": prompt.flow_id,
118→                "other_user_id": prompt.other_user_id,
119→                "room_id": prompt.room_id,
120→                "emoji_lines": prompt.emoji_lines,
121→            })).collect::<Vec<_>>(),
122→            "ownership_mode": ownership_mode_label(snapshot.config.ownership_mode.clone()),
123→            "auth_mode": match client::auth_mode(&snapshot.config) {
124→                Ok(client::AuthMode::Password) => "password",
125→                _ => "access_token",
126→            },
127→            "user_id": snapshot.client.user_id().map(|user_id| user_id.to_string()).or_else(|| snapshot.config.user_id.clone()),
128→            "device_id": snapshot.client.device_id().map(|device_id| device_id.to_string()).or_else(|| snapshot.config.device_id.clone()),
129→            "device_display_name": snapshot.config.device_display_name,
130→            "cross_signing_complete": cross_signing_complete,
131→            "device_verified_by_owner": device_verified_by_owner,
132→            "recovery_state": recovery_state_label(recovery_state),
133→            "ownership_error": snapshot.startup_error,
134→        }
135→    })
136→}
