189→fn parse_account_config(config: serde_json::Value) -> ChannelResult<MatrixAccountConfig> {
190→    if config.get("e2ee").is_some() {
191→        return Err(ChannelError::invalid_input(
192→            "matrix `e2ee` config has been removed because encrypted rooms are not configurable per account",
193→        ));
194→    }
195→
196→    Ok(serde_json::from_value(config)?)
197→}
198→
199→fn merge_json_value(base: &mut serde_json::Value, update: serde_json::Value) {
200→    match (base, update) {
201→        (serde_json::Value::Object(base_obj), serde_json::Value::Object(update_obj)) => {
202→            for (key, value) in update_obj {
203→                merge_json_value(
204→                    base_obj.entry(key).or_insert(serde_json::Value::Null),
205→                    value,
206→                );
207→            }
208→        },
209→        (base, update) => *base = update,
210→    }
211→}
212→
213→fn has_explicit_secret(update: &serde_json::Map<String, serde_json::Value>, field: &str) -> bool {
214→    update
215→        .get(field)
216→        .and_then(serde_json::Value::as_str)
217→        .is_some_and(|value| {
218→            !value.trim().is_empty() && value != moltis_common::secret_serde::REDACTED
219→        })
220→}
221→
222→fn sanitize_secret_update_fields(update: &mut serde_json::Map<String, serde_json::Value>) {
223→    let switching_to_password = has_explicit_secret(update, "password");
224→    let switching_to_access_token = has_explicit_secret(update, "access_token");
225→
226→    if update
227→        .get("access_token")
228→        .and_then(serde_json::Value::as_str)
229→        .is_some_and(|value| {
230→            value.trim().is_empty() && !switching_to_password
231→                || value == moltis_common::secret_serde::REDACTED
232→        })
233→    {
234→        update.remove("access_token");
235→    }
236→
237→    if update
238→        .get("password")
239→        .and_then(serde_json::Value::as_str)
240→        .is_some_and(|value| {
241→            value.trim().is_empty() && !switching_to_access_token
242→                || value == moltis_common::secret_serde::REDACTED
243→        })
244→    {
245→        update.remove("password");
246→    }
247→}
248→
249→fn merge_update_with_existing(
250→    update: serde_json::Value,
251→    existing: &MatrixAccountConfig,
252→) -> ChannelResult<MatrixAccountConfig> {
253→    let mut merged = serde_json::to_value(existing)
254→        .map_err(|error| ChannelError::external("matrix config serialize", error))?;
255→    let mut update = update;
256→    let serde_json::Value::Object(update_obj) = &mut update else {
257→        return Err(ChannelError::invalid_input(
258→            "matrix config update payload must be a JSON object",
259→        ));
260→    };
261→    sanitize_secret_update_fields(update_obj);
262→    merge_json_value(&mut merged, update);
263→    parse_account_config(merged)
264→}
