276→    #[instrument(skip(self, config), fields(account_id))]
277→    async fn start_account(
278→        &mut self,
279→        account_id: &str,
280→        config: serde_json::Value,
281→    ) -> ChannelResult<()> {
282→        let cfg = parse_account_config(config)?;
283→        if cfg.homeserver.is_empty() {
284→            return Err(ChannelError::invalid_input("homeserver URL is required"));
285→        }
286→        client::auth_mode(&cfg)?;
287→
288→        info!(account_id, homeserver = %cfg.homeserver, "starting matrix account");
289→
290→        let (client, authenticated) =
291→            client::build_and_authenticate_client(account_id, &cfg).await?;
292→        let bot_user_id = authenticated.user_id;
293→
294→        let cancel = tokio_util::sync::CancellationToken::new();
295→
296→        {
297→            let otp_cooldown = cfg.otp_cooldown_secs;
298→            let mut cfg = cfg;
299→            cfg.user_id = Some(bot_user_id.to_string());
300→            let mut accounts = self.accounts.write().unwrap_or_else(|e| e.into_inner());
301→            accounts.insert(account_id.to_string(), AccountState {
302→                account_id: account_id.to_string(),
303→                config: cfg,
304→                client: client.clone(),
305→                message_log: self.message_log.clone(),
306→                event_sink: self.event_sink.clone(),
307→                cancel: cancel.clone(),
308→                bot_user_id: bot_user_id.to_string(),
309→                ownership_startup_error: authenticated.ownership_startup_error,
310→                initial_sync_complete: AtomicBool::new(false),
311→                pending_identity_reset: Mutex::new(None),
312→                otp: Mutex::new(OtpState::new(otp_cooldown)),
313→                verification: Mutex::new(Default::default()),
314→            });
315→        }
316→
317→        client::register_event_handlers(&client, account_id, &self.accounts, &bot_user_id);
318→        client::sync_once_and_spawn_loop(&client, account_id, &self.accounts, cancel.clone())
319→            .await?;
320→
321→        Ok(())
322→    }
323→
324→    async fn stop_account(&mut self, account_id: &str) -> ChannelResult<()> {
325→        let cancel = {
326→            let mut accounts = self.accounts.write().unwrap_or_else(|e| e.into_inner());
327→            accounts.remove(account_id).map(|s| s.cancel)
328→        };
329→        if let Some(cancel) = cancel {
330→            cancel.cancel();
331→            info!(account_id, "matrix account stopped");
332→        } else {
333→            warn!(account_id, "matrix account not found");
334→        }
335→        Ok(())
336→    }
337→
338→    async fn retry_account_setup(&mut self, account_id: &str) -> ChannelResult<()> {
339→        let (client, config, pending_handle) = {
340→            let mut accounts = self
341→                .accounts
342→                .write()
343→                .unwrap_or_else(|error| error.into_inner());
344→            let state = accounts
345→                .get_mut(account_id)
346→                .ok_or_else(|| ChannelError::unknown_account(account_id))?;
347→            let pending_handle = state
348→                .pending_identity_reset
349→                .lock()
350→                .unwrap_or_else(|error| error.into_inner())
351→                .take();
352→            (state.client.clone(), state.config.clone(), pending_handle)
353→        };
354→
355→        let pending_handle = pending_handle.ok_or_else(|| {
356→            ChannelError::invalid_input("matrix account has no pending ownership approval to retry")
357→        })?;
358→
359→        pending_handle.reset(None).await.map_err(|error| {
360→            ChannelError::external("matrix recovery reset identity approval", error)
361→        })?;
362→        client
363→            .encryption()
364→            .wait_for_e2ee_initialization_tasks()
365→            .await;
366→
367→        let ownership_attempt =
368→            client::maybe_take_matrix_account_ownership(&client, account_id, &config).await;
369→
370→        {
371→            let mut accounts = self
372→                .accounts
373→                .write()
374→                .unwrap_or_else(|error| error.into_inner());
375→            let state = accounts
376→                .get_mut(account_id)
377→                .ok_or_else(|| ChannelError::unknown_account(account_id))?;
378→            state.ownership_startup_error = ownership_attempt.startup_error.clone();
379→            let mut pending_identity_reset = state
380→                .pending_identity_reset
381→                .lock()
382→                .unwrap_or_else(|error| error.into_inner());
383→            *pending_identity_reset = ownership_attempt.pending_identity_reset;
384→        }
385→
386→        if let Some(error) = ownership_attempt.startup_error {
387→            return Err(ChannelError::invalid_input(error));
388→        }
389→
390→        Ok(())
391→    }
