425→    fn update_account_config(
426→        &self,
427→        account_id: &str,
428→        config: serde_json::Value,
429→    ) -> ChannelResult<()> {
430→        let mut accounts = self.accounts.write().unwrap_or_else(|e| e.into_inner());
