471→#[async_trait]
472→impl ChannelStatus for MatrixPlugin {
473→    async fn probe(&self, account_id: &str) -> ChannelResult<ChannelHealthSnapshot> {
474→        let snapshot = {
475→            let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
476→            accounts.get(account_id).map(|state| {
477→                let prompts = {
478→                    let verification = state
479→                        .verification
480→                        .lock()
481→                        .unwrap_or_else(|error| error.into_inner());
482→                    let mut prompts = verification.prompts.values().cloned().collect::<Vec<_>>();
483→                    prompts.sort_by(|left, right| left.other_user_id.cmp(&right.other_user_id));
484→                    prompts
485→                };
486→                (
487→                    state.client.matrix_auth().logged_in(),
488→                    state.bot_user_id.clone(),
489→                    MatrixStatusSnapshot {
490→                        client: state.client.clone(),
491→                        config: state.config.clone(),
492→                        prompts,
493→                        startup_error: state.ownership_startup_error.clone(),
494→                    },
495→                )
496→            })
497→        };
498→
499→        if let Some((connected, bot_user_id, snapshot)) = snapshot {
500→            let details = if connected {
501→                format!("syncing as {bot_user_id}")
502→            } else {
503→                "not logged in".to_string()
504→            };
505→            Ok(ChannelHealthSnapshot {
506→                connected,
507→                account_id: account_id.to_string(),
508→                details: Some(details),
509→                extra: Some(matrix_status_extra(snapshot).await),
510→            })
511→        } else {
512→            Ok(ChannelHealthSnapshot {
513→                connected: false,
514→                account_id: account_id.to_string(),
515→                details: Some("account not started".into()),
516→                extra: None,
517→            })
518→        }
519→    }
520→}
