                // Let 3 sync failures + backoffs complete, then cancel.
                // Backoff sequence: 5s, 10s, 20s = 35s total + tiny sync time.
                tokio::time::sleep(std::time::Duration::from_secs(36)).await;
                cancel_inner.cancel();
            });

            retry_loop(
                || {
